// Use the preserved data, not the overwritten payload from the previous DB node
const data = msg.originalPayload;


// Helper to prevent 'null' or 'undefined' from causing SQL errors.
const toSQL = (val, isString = false) => {
    if (val === undefined || val === null) return 'NULL';
    if (isString) return `'${String(val).replace(/'/g, "''")}'`;
    return val;
};

const query = `
INSERT INTO remoteid 
(ts, src, trackid, aircraftid, idtype, uastype, lat, lon, baroalt, geoalt, track, hvelo, vvelo, operatorid, operator_lat, operator_lon, operator_loctype, frametype, selfidtype, rssi, mac, channel) 
VALUES 
(
    ${toSQL(data.ts)},
    ${toSQL(data.src, true)},
    ${toSQL(data.trackID)},
    ${toSQL(data.aircraftID, true)},
    ${toSQL(data.idType)},
    ${toSQL(data.uasType)},
    ${toSQL(data.lat)},
    ${toSQL(data.lon)},
    ${toSQL(data.baroAlt)},
    ${toSQL(data.geoAlt)},
    ${toSQL(data.track)},
    ${toSQL(data.hVelo)},
    ${toSQL(data.vVelo)},
    ${toSQL(data.operatorID, true)},
    ${toSQL(data.latOp)},
    ${toSQL(data.lonOp)},
    ${toSQL(data.locTypeOp)},
    ${toSQL(data.frameType)},
    ${toSQL(data.selfIdType)},
    ${toSQL(data.rssi)},
    ${toSQL(data.mac, true)},
    ${toSQL(data.channel)}
);`;

msg.query = query;
return msg;

// The JSON data you want to send, enclosed in single quotes to make it a string.349908,"ver":1,"rem
msg.payload = '{"src":"gs2l0071","ts":1768256123,"ver":1,"remoteid":{"framePrefix":"WB","aircraftID":"18099300000629","idType":1,"uasType":2,"lat":59.345039,"lon":17.966075,"height":3.0,"baroAlt":58.0,"geoAlt":-9.5,"track":361,"hVelo":0.0,"vVelo":0.0,"statusFlag":2,"operator":{"id":"DNK000003982727e","idType":0,"lat":55.6939372,"lon":12.4168339,"locType":1},"times":3481.2,"rssi":-53,"selfIdType":0,"frameType":15,"mac":"8c:1e:d9:37:66:43","channel":6}}';

// Send the message on to the next node in the flow.
return msg;

// This function handles saving or deleting geofences.

// CASE 1: A polygon was drawn and named in the UI.
if (msg.payload && msg.payload.action === 'draw') {

    const geofenceName = msg.payload.name || `geofence_${Date.now()}`;
    const area = msg.payload.area; // This is an array of {lat, lon} objects.

    // We need to convert the points into a Well-Known Text (WKT) string for PostGIS.
    // The format is "POLYGON((lon1 lat1, lon2 lat2, ...))"
    let pointsWkt = area.map(p => `${p.lng} ${p.lat}`).join(', ');

    // Ensure the polygon is closed for valid WKT.
    if (area.length > 0 && (area[0].lng !== area[area.length - 1].lng || area[0].lat !== area[area.length - 1].lat)) {
        pointsWkt += `, ${area[0].lng} ${area[0].lat}`;
    }

    const wkt = `POLYGON((${pointsWkt}))`;

    // Construct the SQL query using the ST_GeomFromText PostGIS function.
    // It inserts a new geofence or updates an existing one with the same name.
    const sql = `
        INSERT INTO public.geofences (name, geometry, created_at, updated_at)
        VALUES (
            '${geofenceName}',
            ST_SetSRID(ST_GeomFromText('${wkt}'), 4326),
            NOW(),
            NOW()
        )
        ON CONFLICT (name) DO UPDATE SET
            geometry = EXCLUDED.geometry,
            updated_at = CURRENT_TIMESTAMP
        RETURNING id;
    `;

    msg.query = sql;
    msg.payload = { status: 'saving', name: geofenceName };
    return msg;

}
// CASE 2: A polygon was deleted from the map UI.
else if (msg.payload && msg.payload.action === 'drawdelete' && msg.payload.name) {
    const geofenceName = msg.payload.name;

    // The DELETE query is simpler and does not need to change.
    const sql = `DELETE FROM public.geofences WHERE name = '${geofenceName}' RETURNING id;`;

    msg.query = sql;
    msg.payload = { status: 'deleting', name: geofenceName };
    return msg;
}
else {
    node.warn("Unsupported map action received. Only Polygon draw/delete supported for geofences.");
    return null;
}

let features = msg.payload; // your DB array of { name, geojson }
let output = [];

for (let f of features) {
    try {
        let geo = JSON.parse(f.geojson);

        if (geo.type !== "Polygon") continue; // skip if not a polygon

        let coords = geo.coordinates[0]; // first ring
        let area = coords.map(pair => [pair[1], pair[0]]); // convert lon/lat → lat/lon

        output.push({
            name: f.name,
            layer: "drawing",
            clickable: true,
            editable: true,
            area: area
        });
    } catch (err) {
        node.warn(`Failed to parse geojson for ${f.name}: ${err.message}`);
    }
}

msg.payload = output;
return msg;

// This function is triggered to reload geofences into memory.
// It will query the DB and store results in flow context.

// Use ST_AsGeoJSON to convert the PostGIS geometry column to GeoJSON text.
// Alias it as 'geojson' so subsequent nodes like 'Store Geofences in Flow Context'
// can correctly reference `row.geojson`.
msg.query = `SELECT name, ST_AsGeoJSON(geometry) as geojson FROM public.geofences;`;
return msg;

// Parse GeoJSON strings into objects and store in flow context
const geofences = msg.payload.map(row => {
    let parsedGeometry = null;
    try {
        // Parse the geojson string into a JavaScript object
        parsedGeometry = JSON.parse(row.geojson);
    } catch (e) {
        node.error(`Failed to parse geojson for geofence '${row.name}': ${e.message}`);
        // If parsing fails, return null geometry or handle as appropriate
        // To ensure messages keep flowing even if parse fails, you could return an empty geometry or null
        return { name: row.name, geometry: null }; // Add this line if parsing fails to prevent flow break
    }

    return {
        name: row.name,
        geometry: parsedGeometry // Now 'geometry' will be a proper GeoJSON object
    };
});

flow.set('geofences', geofences);
node.status({ fill: "blue", shape: "dot", text: `Loaded ${geofences.length} geofences.` });
node.log(`Loaded ${geofences.length} geofences into flow context.`);

// VERY IMPORTANT: Return the message here for the next node in the sequence
// The msg.payload *after* this node should be the 'geofences' array
msg.payload = geofences; // Set msg.payload to the processed array for the next function
return msg;

// This advanced SQL query uses PostGIS functions to build a complete
// GeoJSON FeatureCollection directly in the database. It is very efficient.
msg.query = `
    SELECT json_build_object(
        'type', 'FeatureCollection',
        'features', json_agg(ST_AsGeoJSON(t.*)::json)
    ) AS geojson
    FROM (
        SELECT name, geometry FROM public.geofences
    ) AS t;
`;
return msg;

// The database returns a single row with a single column named "geojson"
// that contains our complete FeatureCollection object.
// We just need to extract it and place it into the payload.
if (msg.payload && msg.payload[0] && msg.payload[0].geojson) {
    msg.payload = msg.payload[0].geojson;
} else {
    // If there are no features, send a valid empty FeatureCollection.
    msg.payload = { "type": "FeatureCollection", "features": [] };
}
return msg;

// The msg.payload now contains the result from our combined lookup
const lookupResult = msg.payload[0];

const dbId = lookupResult.new_id;
const locationName = lookupResult.location_name || 'Unknown';
const sourceData = msg.originalSensorData || {}; // Use empty object as fallback

// Dynamically determine the detection category based on protocol type
let detectionCategory = "Other Detection"; // <--- Safely defaults to "Other Detection"
if (sourceData.protocol_type === "drone_id") {
    detectionCategory = "DroneID Detection";
} else if (sourceData.protocol_type === "remote_id") {
    detectionCategory = "RemoteID Detection";
} else if (sourceData.protocol_type) {
    detectionCategory = `${sourceData.protocol_type} Detection`;
}

let finalAlarm = {};

if (msg.isGeofenceAlarm) {
    finalAlarm = {
        "Time": new Date().toISOString(),
        "Id": dbId,
        "Category": detectionCategory,
        "Event Name": msg.geofenceName ? `Geofence @ ${msg.geofenceName}` : "Geofence Violation",
        "Status": "Active",
        "unique_input_id": sourceData.trackID ? sourceData.trackID.toString() : (sourceData.aircraftID || dbId.toString()),
        "AircraftID": sourceData.aircraftID,
        "Latitude": sourceData.lat,
        "Longitude": sourceData.lon,
        "Source": sourceData.src,
        "Location": locationName,
        "Acknowledged": 'false',
        "Archived": 'false'
    };
} else if (msg.isWifiAlarm) {
    // New block for Wi-Fi client alarms
    finalAlarm = {
        "Time": new Date().toISOString(),
        "Id": dbId,
        "Category": "Wi-Fi RSSI Signal",
        "Event Name": `High RSSI ${sourceData.rssi} for ${sourceData.ssid}`,
        "Status": "Active",
        "unique_input_id": sourceData.mac,
        "AircraftID": "N/A",
        "Latitude": "59.345013",
        "Longitude": "17.966132",
        "Source": sourceData.src,
        "Location": locationName,
        "Acknowledged": 'false',
        "Archived": 'false'
    };
} else {
    // Existing block for other system alarms
    finalAlarm = {
        "Time": new Date().toISOString(),
        "Id": dbId,
        "Category": "System", // You can change this to "Other System" if you prefer
        "Event Name": "System Alarm",
        "Status": "Active",
        "unique_input_id": sourceData.trackID ? sourceData.trackID.toString() : dbId.toString(),
        "AircraftID": sourceData.aircraftID || 'N/A',
        "Latitude": sourceData.lat || null,
        "Longitude": sourceData.lon || null,
        "Source": sourceData.src || 'System',
        "Location": "Stack Alarm Region",
        "Acknowledged": 'false',
        "Archived": 'false'
    };
}

msg.payload = finalAlarm;
msg.payload_original = finalAlarm;

return msg;

const alarm = msg.payload;

// Escape single quotes in string fields for SQL insertion
const category = alarm.Category.replace(/'/g, "''");
const eventName = alarm['Event Name'].replace(/'/g, "''");
const status = alarm.Status.replace(/'/g, "''");
// NEW: Get and escape the source field
const source = alarm.Source ? alarm.Source.replace(/'/g, "''") : null;

// Handle potentially null unique_input_id for SQL
const uniqueIdValue = (alarm.unique_input_id === null || alarm.unique_input_id === undefined) ? 'NULL' : `'${alarm.unique_input_id}'`;

// Handle the new VARCHAR boolean-like fields.
const acknowledgedValue = (alarm.Acknowledged === 'true' || alarm.Acknowledged === true) ? `'true'` : `'false'`;
const archivedValue = (alarm.Archived === 'true' || alarm.Archived === true) ? `'true'` : `'false'`;

// Handle Latitude and Longitude
const latitudeValue = (alarm.Latitude === null || alarm.Latitude === undefined) ? 'NULL' : alarm.Latitude;
const longitudeValue = (alarm.Longitude === null || alarm.Longitude === undefined) ? 'NULL' : alarm.Longitude;

// NEW: Handle the source value for SQL
const sourceValue = (source === null) ? 'NULL' : `'${source}'`;

const sql = `
INSERT INTO public.alarms(
    id,
    event_time,
    category,
    event_name,
    unique_input_id,
    latitude,
    longitude,
    acknowledged,
    archived,
    status,
    sensor_source -- NEW COLUMN
)
VALUES (
    ${alarm.Id},
    '${alarm.Time}',
    '${category}',
    '${eventName}',
    ${uniqueIdValue},
    ${latitudeValue},
    ${longitudeValue},
    ${acknowledgedValue},
    ${archivedValue},
    '${status}',
    ${sourceValue} -- NEW VALUE
)
RETURNING id;
`;

msg.query = sql;
msg.payload = alarm;

// ADD THIS LINE to preserve the full alarm object before the database node overwrites it.
msg.originalAlarmObject = msg.payload;

return msg;

const sensorId = msg.originalSensorData.src;

if (!sensorId) {
    node.error("Sensor ID (src) is missing, cannot look up data.");
    return null;
}

// This single query gets both the location name and the next alarm ID
msg.query = `
    SELECT
        nextval('public.alarms_id_seq') AS new_id,
        (
            SELECT ap.location
            FROM public.sensors s
            JOIN public.locations ap ON s.location_id = ap.id
            WHERE s.sensor_nm = '${sensorId}'
        ) AS location_name;
`;

return msg;

// This node now performs two functions:
// 1. Handles the trackID logic (new or existing).
// 2. Prepares a query to ensure the operatorID exists in the 'remoteid_operator' table.

let activeTracks = flow.get('activeTracks') || {};
const raw = msg.payload;

// --- 1. Flatten the incoming message ---
if (!raw || !raw.remoteid) {
    node.warn("Received message without 'remoteid' object. Ignoring.");
    return null;
}
const rid = raw.remoteid;
const op = rid.operator || {};
const flat_data = {
    src: raw.src,
    ts: Date.now(),
    aircraftID: rid.aircraftID,
    idType: rid.idType,
    uasType: rid.uasType,
    lat: rid.lat,
    lon: rid.lon,
    baroAlt: rid.baroAlt,
    geoAlt: rid.geoAlt,
    track: rid.track,
    hVelo: rid.hVelo,
    vVelo: rid.vVelo,
    operatorID: op.id || "N/A",
    latOp: op.lat,
    lonOp: op.lon,
    locTypeOp: op.locType,
    frameType: rid.frameType,
    selfIdType: rid.selfIdType,
    rssi: rid.rssi,
    mac: rid.mac,
    channel: rid.channel
};

const operatorIdToInsert = flat_data.operatorID;
msg.payload = flat_data;
// We save the flight data here, because the next DB node will overwrite msg.payload
msg.originalPayload = flat_data;
msg.query = `INSERT INTO public.remoteid_operator (id) VALUES ('${operatorIdToInsert}') ON CONFLICT (id) DO NOTHING;`;

// --- 3. Handle TrackID Logic ---
if (!flat_data.aircraftID) {
    node.warn("Message is missing aircraftID.");
    return null;
}
const aircraftId = flat_data.aircraftID;
const now = Date.now();
const TIMEOUT_MS = 15000;

let trackInfo = activeTracks[aircraftId];
let isExpired = !trackInfo || (now - trackInfo.lastSeen >= TIMEOUT_MS);

if (trackInfo && !isExpired) {
    trackInfo.lastSeen = now;
    flow.set('activeTracks', activeTracks);
    msg.payload.trackID = trackInfo.trackID;
    msg.originalPayload.trackID = trackInfo.trackID; // Also update the preserved data

    // Path for EXISTING tracks (Output 1)
    return [msg, null];
} else {
    msg.operatorQuery = msg.query;
    msg.query = `SELECT nextval('remoteid_trackid_seq') AS new_track_id;`;
    flow.set('pending_track_data', msg.payload);

    // *** THIS IS THE BUG FIX ***
    // Path for NEW tracks (Output 2)
    return [null, msg];
}

// Get the data we stored before the database query
const data = flow.get('pending_track_data');
if (!data) {
    node.error("Could not retrieve pending track data from flow context.");
    return null;
}

// Extract the new track ID from the database response
const newTrackId = msg.payload[0]?.new_track_id;
if (newTrackId === undefined) {
    node.error("Database did not return a new_track_id.", msg);
    return null;
}

// Assign the new ID to our data object
data.trackID = newTrackId;

// --- Update the activeTracks list in flow context ---
let activeTracks = flow.get('activeTracks') || {};
activeTracks[data.aircraftID] = {
    trackID: newTrackId,
    lastSeen: Date.now()
};
flow.set('activeTracks', activeTracks);

// Set the final object as the message payload
msg.payload = data;

// We save the flight data here, because the next DB node will overwrite msg.payload
msg.originalPayload = msg.payload;

// *** THIS IS THE FIX ***
// Restore the operator upsert query that was saved in the first node
msg.query = msg.operatorQuery;

return msg;

let activeTracks = flow.get('activeTracks') || {};
const now = Date.now();
const TIMEOUT_MS = 25000; // 15 seconds
let cleanedCount = 0;

for (const aircraftId in activeTracks) {
    if (now - activeTracks[aircraftId].lastSeen >= TIMEOUT_MS) {
        delete activeTracks[aircraftId];
        cleanedCount++;
    }
}

if (cleanedCount > 0) {
    flow.set('activeTracks', activeTracks);
    node.log(`Cleaned up ${cleanedCount} stale tracks.`);
    node.status({ text: `Cleaned ${cleanedCount} tracks` });
} else {
    node.status({ text: 'No stale tracks found' });
}

return null; // Don't pass on a message

// --- Recipient and Location Configuration ---
let recipients = {
  //"daniel": { "smsnbr": "+46704459150", "locations": ["Glostrup"], "email": "daniel@securify.se" },
  "dan": { "smsnbr": "+46702534330", "locations": ["Location1"], "email": "dan@securify.se" },
  //"kenneth": { "smsnbr": "+46705786203", "locations": ["Glostrupn"], "email": "kenneth@securify.se" },
  //"richard": { "smsnbr": NaN, "locations": ["Glostrup"], "email": "richard@securify.se" }
  };

let locations = {
  "Location1": { "abbrevation": "Location1", "friendlyName": "Location1" }

};

// --- Get Alarm Location ---
const alarmLocation = msg.payload.Location;
if (!alarmLocation) {
    node.warn("Alarm location is missing from msg.payload.Location. Cannot send notification.");
    return null;
}
let matchedLocation = locations[alarmLocation] || { friendlyName: alarmLocation, abbrevation: alarmLocation };


// --- Get Alarm Identifier and Build Links ---
const alarmIdentifier = msg.payload.unique_input_id;
if (!alarmIdentifier) {
    node.error("Cannot create alarm link, unique_input_id is missing from the alarm payload!");
    return null;
}
let alarmLink = `https://dfuse.se/d/alarm-details/alarm-details?orgId=1&refresh=1s&var-Details=${alarmIdentifier}`;
const mapsLink = `https://www.google.com/maps?q=${msg.payload.Latitude},${msg.payload.Longitude}`;


// --- Prepare Details for the Email ---
const alarmId = msg.payload.Id;
const eventName = msg.payload['Event Name'];
// Format the timestamp to be more readable for Swedish locale
const alarmTime = new Date(msg.payload.Time).toLocaleString('sv-SE', { timeZone: 'Europe/Stockholm' });


// --- Create Notification Messages ---
let smsText = `dFuse Alarm!\\n${matchedLocation.friendlyName}\\n${alarmLink}`;

// --- Updated emailHtml with AircraftID row ---
let emailHtml = `
  <div style="font-family: Arial, sans-serif; color: #333; max-width: 600px; margin: auto; border: 1px solid #ddd; padding: 20px; border-radius: 5px;">
    <h2 style="color: #d00;"><span style="color: #ff0000;">❗ dFuse Alarm Notification</span></h2>
    <p>An alarm has been triggered in dFuse with the following details:</p>
    <table style="width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 14px;">
      <tbody>
        <tr style="border-bottom: 1px solid #eee;">
          <td style="padding: 8px 0; width: 120px;"><strong>Location:</strong></td>
          <td style="padding: 8px 0;">${matchedLocation.friendlyName}</td>
        </tr>
        <tr style="border-bottom: 1px solid #eee;">
          <td style="padding: 8px 0;"><strong>Event:</strong></td>
          <td style="padding: 8px 0;">${eventName}</td>
        </tr>
        <tr style="border-bottom: 1px solid #eee;">
          <td style="padding: 8px 0;"><strong>Flight ID:</strong></td>
          <td style="padding: 8px 0;">${alarmIdentifier}</td>
        </tr>
        <tr style="border-bottom: 1px solid #eee;">
          <td style="padding: 8px 0;"><strong>Aircraft ID:</strong></td>
          <td style="padding: 8px 0;">${msg.payload.AircraftID}</td>
        </tr>
        <tr style="border-bottom: 1px solid #eee;">
          <td style="padding: 8px 0;"><strong>Alarm ID:</strong></td>
          <td style="padding: 8px 0;">${alarmId}</td>
        </tr>
        <tr style="border-bottom: 1px solid #eee;">
          <td style="padding: 8px 0;"><strong>Time:</strong></td>
          <td style="padding: 8px 0;">${alarmTime}</td>
        </tr>
        <tr style="border-bottom: 1px solid #eee;">
          <td style="padding: 8px 0;"><strong>Coordinates:</strong></td>
          <td style="padding: 8px 0;"><a href="${mapsLink}" target="_blank">${msg.payload.Latitude}, ${msg.payload.Longitude}</a></td>
        </tr>
      </tbody>
    </table>
    <p style="text-align: center;"><a style="background-color: #007bff; color: white; padding: 12px 20px; text-decoration: none; border-radius: 5px; display: inline-block;" href="${alarmLink}">View Alarm in dFuse</a></p>
    <div style="text-align: right; margin-top: 30px;">
      <p style="font-size: 0.9em; color: #888; margin: 0 0 5px 0;">Sent by dFuse</p>
      <img style="width: 80px;" src="https://www.securify.se/web/image/website/1/logo/Securify?unique=c34e499" alt="Company Logo" height="60" />
    </div>
  </div>
`;

let smsMessages = [];
let bccList = []; // Array to hold all BCC emails

// Loop through recipients to build the SMS array and BCC email array
for (const [name, recipient] of Object.entries(recipients)) {
  if (recipient.locations.includes(matchedLocation.abbrevation)) {
    // SMS
    if (typeof recipient.smsnbr === "string" && recipient.smsnbr.trim() !== "") {
      smsMessages.push({
        topic: recipient.smsnbr,
        payload: smsText
      });
    }
    // Email collection
    if (typeof recipient.email === "string" && recipient.email.trim() !== "") {
      bccList.push(recipient.email);
    }
  }
}

// Build a single email message if there are any recipients
let emailMessage = null;
if (bccList.length > 0) {
  emailMessage = {
    to: "info@securify.se",
    bcc: bccList.join(", "),
    from: "info@securify.se",
    topic: "❗ RemoteID Alarm: " + matchedLocation.friendlyName,
    payload: emailHtml,
    originalEmailPayload: emailHtml
  };
}

// Return SMS messages on Output 1, and the single grouped email on Output 2
return [smsMessages, emailMessage];

// The original full alarm object was preserved in the previous node.
const currentAlarm = msg.originalAlarmObject;
if (!currentAlarm) {
    node.error("Original alarm object was not found in msg.originalAlarmObject. Cannot proceed.");
    return null;
}

// The database node returned the new ID in msg.payload
const newAlarmId = msg.payload[0]?.id;
if (newAlarmId === undefined) {
    node.error("Database did not return a new alarm ID. Cannot proceed.");
    return null;
}

const previousAlarmId = flow.get('highest_processed_alarm_id') || 0;

// Restore the full alarm object to msg.payload so the next node can use it.
msg.payload = currentAlarm;

// Set the scenario property for the next node.
msg.received_alarm = {
    scenario: msg.isGeofenceAlarm ? msg.geofenceName : currentAlarm['Event Name']
};

flow.set('highest_processed_alarm_id', newAlarmId);

// Check if the alarm ID is new.
if (newAlarmId > previousAlarmId) {
    node.status({ fill: "yellow", shape: "dot", text: `New Alarm: ${newAlarmId}` });
    return [msg, null]; // Output 1: Send notification
} else {
    node.status({ fill: "blue", shape: "dot", text: `No new high ID: ${newAlarmId}` });
    return [null, msg]; // Output 2: No notification needed
}

// Get the aircraft ID from the incoming alarm object.
const aircraftId = msg.payload.AircraftID;

// Preserve the original alarm payload for later. This avoids the circular reference bug.
msg.preservedPayload = msg.payload;

if (!aircraftId) {
    node.warn("Alarm object is missing AircraftID. Whitelist check skipped.");
    // If there is no ID, we can't check the database.
    // We will create a fake database result that means "not found" (count=0).
    // The switch node will then pass this message along, and the restore node will fix the payload.
    msg.payload = [{ count: '0' }];
    return msg;
}

// If we have an ID, create the real query. The database node will overwrite the payload.
msg.query = `SELECT COUNT(*) FROM public.aircraft_whitelist WHERE LOWER(TRIM(aircraft_id)) = LOWER(TRIM('${aircraftId}'));`;

return msg;

// This finds "}{" and replaces it with "}\n{" to insert a newline
msg.payload = msg.payload.replace(/}{/g, "}\\n{");
return msg;

const trackId = parseInt(msg.payload.id, 10);

if (isNaN(trackId)) {
    node.error('Invalid Track ID');
    msg.payload = { error: 'Invalid Track ID' };
    msg.statusCode = 400;
    return [null, msg]; // Send error to HTTP Response
}

msg.query = `
WITH track_data AS (
  SELECT * FROM public.remoteid WHERE trackid = ${trackId} ORDER BY ts ASC
),
latest_data AS (
  SELECT * FROM track_data ORDER BY ts DESC LIMIT 1
),
stats_data AS (
  SELECT 
    to_char(to_timestamp(MIN(ts) / 1000) AT TIME ZONE 'Europe/Stockholm', 'YYYY/MM/DD, HH24:MI:SS') AS "First Detected",
    to_char(to_timestamp(MAX(ts) / 1000) AT TIME ZONE 'Europe/Stockholm', 'YYYY/MM/DD, HH24:MI:SS') AS "Last Seen",
    (to_timestamp(MAX(ts) / 1000) - to_timestamp(MIN(ts) / 1000))::text AS "Duration",
    CASE WHEN aw.aircraft_id IS NOT NULL THEN 'Yes' ELSE 'No' END AS "Whitelisted",
    COALESCE(aw.comment, 'N/A') AS "Whitelist Comment",
    (array_agg(a.id ORDER BY a.event_time DESC))[1]::text AS "Alarm ID",
    (array_agg(a.status ORDER BY a.event_time DESC))[1] AS "Alarm Status"
  FROM track_data AS r
  LEFT JOIN public.alarms AS a ON r.trackid::text = a.unique_input_id
  LEFT JOIN public.aircraft_whitelist AS aw ON LOWER(TRIM(r.aircraftid)) = LOWER(TRIM(aw.aircraft_id))
  GROUP BY r.trackid, r.aircraftid, aw.aircraft_id, aw.comment
)
SELECT json_build_object(
    'details', (
        SELECT json_build_object(
            'Alarm Time', to_char(to_timestamp(ld.ts / 1000) AT TIME ZONE 'Europe/Stockholm', 'YYYY/MM/DD, HH24:MI:SS'),
            'Flight ID (TrackID)', ld.trackid::text,
            'Aircraft ID (RemoteID)', ld.aircraftid::text,
            'Height', ld.height::text,
            'Baro. Altitude', ld.baroalt::text,
            'Speed', ld.hvelo::text,
            'Pilot Operator ID', ld.operatorid::text,
            'Latitude', ld.lat::text,
            'Longitude', ld.lon::text,
            'Pilot Latitude', ld.operator_lat::text,
            'Pilot Longitude', ld.operator_lon::text
        )
        FROM latest_data ld
    ),
    'stats', (SELECT to_jsonb(sd.*) FROM stats_data sd),
    'track', (SELECT json_agg(json_build_object('lat', td.lat, 'lon', td.lon)) FROM track_data td)
) AS report_data;
`;

