// === HELPER FUNCTIONS ===
function offsetCoord(lat, lon, dx, dy) {
    const earthRadius = 6378137;
    const newLat = lat + (dy / earthRadius) * (180 / Math.PI);
    const newLon = lon + (dx / (earthRadius * Math.cos(Math.PI * lat / 180))) * (180 / Math.PI);
    return [newLat, newLon];
}

function generateRandomHexString(length) {
    let result = '';
    const characters = '0123456789ABCDEF';
    for (let i = 0; i < length; i++) {
        result += characters.charAt(Math.floor(Math.random() * characters.length));
    }
    return result;
}

// *** FIXED FLIGHT PATH LOGIC WITH DYNAMIC TRACK & NOISE ***
function generateBowTrack(startLat, startLon, baseAlt, aircraftID, operatorID, trackID) {
    const track = [];
    const flightDist = 600;
    const bowWidth = 150;
    const bearing = 300;

    const dxPeak = Math.sin(bearing * Math.PI / 180) * flightDist;
    const dyPeak = Math.cos(bearing * Math.PI / 180) * flightDist;
    const [peakLat, peakLon] = offsetCoord(startLat, startLon, dxPeak, dyPeak);

    let coords = [];
    for (let i = 0; i < pointsPerTrack; i++) {
        const halfPoints = pointsPerTrack / 2;
        let cLat, cLon, cAlt;

        if (i < halfPoints) {
            const phaseProgress = i / (halfPoints - 1);
            const bowOffset = Math.sin(phaseProgress * Math.PI) * bowWidth;
            let linearLat = startLat + (peakLat - startLat) * phaseProgress;
            let linearLon = startLon + (peakLon - startLon) * phaseProgress;
            const dxBow = Math.sin((bearing + 90) * Math.PI / 180) * bowOffset;
            const dyBow = Math.cos((bearing + 90) * Math.PI / 180) * bowOffset;
            [cLat, cLon] = offsetCoord(linearLat, linearLon, dxBow, dyBow);
            cAlt = baseAlt + (Math.sin(phaseProgress * Math.PI / 2) * 20);
        } else {
            const phaseProgress = (i - halfPoints) / (halfPoints - 1);
            cLat = peakLat + (startLat - peakLat) * phaseProgress;
            cLon = peakLon + (startLon - peakLon) * phaseProgress;
            cAlt = baseAlt + 20 - (phaseProgress * 20);
        }
        coords.push({ lat: cLat, lon: cLon, alt: cAlt });
    }

    for (let i = 0; i < pointsPerTrack; i++) {
        let heading;
        if (i < pointsPerTrack - 1) {
            const dLon = (coords[i + 1].lon - coords[i].lon);
            const y = Math.sin(dLon * Math.PI / 180) * Math.cos(coords[i + 1].lat * Math.PI / 180);
            const x = Math.cos(coords[i].lat * Math.PI / 180) * Math.sin(coords[i + 1].lat * Math.PI / 180) -
                Math.sin(coords[i].lat * Math.PI / 180) * Math.cos(coords[i + 1].lat * Math.PI / 180) * Math.cos(dLon * Math.PI / 180);

            // Calculate true heading + add random noise
            let trueHeading = (Math.atan2(y, x) * 180 / Math.PI + 360) % 360;
            let noise = (Math.random() * headingNoise * 2) - headingNoise;
            heading = (trueHeading + noise + 360) % 360;
        } else {
            heading = track[i - 1].remoteid.track;
        }

        const msg = {
            src: src,
            ts: 0,
            ver: 1,
            remoteid: {
                framePrefix: "WB",
                aircraftID: aircraftID,
                trackID: trackID,
                idType: 1,
                uasType: 2,
                lat: coords[i].lat,
                lon: coords[i].lon,
                height: Math.round(coords[i].alt),
                baroAlt: coords[i].alt + 10,
                geoAlt: coords[i].alt,
                track: Math.round(heading),
                hVelo: 10.0,
                vVelo: (i < pointsPerTrack / 2) ? 0.5 : -0.5, // Added slight vertical velocity
                statusFlag: 2,
                operator: {
                    id: operatorID,
                    idType: 0,
                    lat: startLat,
                    lon: startLon,
                    locType: 1
                },
                times: i,
                rssi: -30 - Math.floor(Math.random() * 20),
                frameType: 15,
                mac: "8c:1e:d9:37:66:43",
                channel: 6
            }
        };
        track.push(msg);
    }
    return track;
}

