const start_lat = 59.340552;
const start_lon = 17.969826;

const totalTracks = 1;
const pointsPerTrack = 100;
const spreadMeters = 50;
const pauseBetweenTracks = 12000;

function offsetCoord(lat, lon, dx, dy) {
    const earthRadius = 6378137;
    const newLat = lat + (dy / earthRadius) * (180 / Math.PI);
    const newLon = lon + (dx / (earthRadius * Math.cos(Math.PI * lat / 180))) * (180 / Math.PI);
    return [newLat, newLon];
}

function generateRandomHexString(length) {
    let result = '';
    const characters = '0123456789ABCDEF';
    for (let i = 0; i < length; i++) {
        result += characters.charAt(Math.floor(Math.random() * characters.length));
    }
    return result;
}

function generateBowTrack(startLat, startLon, baseAlt, droneSerial) {
    const track = [];
    const flightDist = 700;
    const bowWidth = 130;
    const bearing = 310;
    const droneSpeed = 10.0;

    const dxPeak = Math.sin(bearing * Math.PI / 180) * flightDist;
    const dyPeak = Math.cos(bearing * Math.PI / 180) * flightDist;
    const [peakLat, peakLon] = offsetCoord(startLat, startLon, dxPeak, dyPeak);

    let coords = [];
    for (let i = 0; i < pointsPerTrack; i++) {
        const halfPoints = pointsPerTrack / 2;
        let cLat, cLon, cAlt, cAgl;

        if (i < halfPoints) {
            const phaseProgress = i / (halfPoints - 1);
            const bowOffset = Math.sin(phaseProgress * Math.PI) * bowWidth;
            let linearLat = startLat + (peakLat - startLat) * phaseProgress;
            let linearLon = startLon + (peakLon - startLon) * phaseProgress;
            const dxBow = Math.sin((bearing + 90) * Math.PI / 180) * bowOffset;
            const dyBow = Math.cos((bearing + 90) * Math.PI / 180) * bowOffset;
            [cLat, cLon] = offsetCoord(linearLat, linearLon, dxBow, dyBow);
            cAgl = Math.sin(phaseProgress * Math.PI / 2) * 20;
            cAlt = baseAlt + cAgl;
        } else {
            const phaseProgress = (i - halfPoints) / (halfPoints - 1);
            let linearLat = peakLat + (startLat - peakLat) * phaseProgress;
            let linearLon = peakLon + (startLon - peakLon) * phaseProgress;
            cLat = linearLat;
            cLon = linearLon;
            cAgl = 20 - (phaseProgress * 20);
            cAlt = baseAlt + cAgl;
        }
        coords.push({ lat: cLat, lon: cLon, alt: cAlt, agl: cAgl });
    }

    for (let i = 0; i < pointsPerTrack; i++) {
        let currentBearing = bearing;
        let isReturning = i >= (pointsPerTrack / 2);

        if (isReturning) {
            currentBearing = (bearing + 180) % 360;
        }

        const speed_n = Math.cos(currentBearing * Math.PI / 180) * droneSpeed;
        const speed_e = Math.sin(currentBearing * Math.PI / 180) * droneSpeed;
        const speed_u = (i < pointsPerTrack / 2) ? 0.5 : -0.5;

        const payloadObject = {
            "detection_type": "telemetry",
            "protocol_type": "drone_id",
            "protocol_version": "ocusync_v2_3",
            "encryption": null,
            "signal_confidence": 1.0,
            "frequency_mhz": 2444.5,
            "bandwidth_mhz": null,
            "rssi_dbm": -61,
            "model": "DJI Mavic 2",
            "serial": droneSerial,
            "mac_address": null,
            "drone_coords": {
                "lat": parseFloat(coords[i].lat.toFixed(6)),
                "lon": parseFloat(coords[i].lon.toFixed(6)),
                "alt_m_msl": parseFloat(coords[i].alt.toFixed(2)),
                "alt_m_agl": parseFloat(coords[i].agl.toFixed(2))
            },
            "drone_velocity": {
                "speed": droneSpeed,
                "speed_e": parseFloat(speed_e.toFixed(2)),
                "speed_n": parseFloat(speed_n.toFixed(2)),
                "speed_u": speed_u
            },
            "drone_home_coords": {
                "lat": parseFloat(startLat.toFixed(6)),
                "lon": parseFloat(startLon.toFixed(6))
            },
            "controller_coords": {
                "lat": parseFloat(startLat.toFixed(6)),
                "lon": parseFloat(startLon.toFixed(6)),
                "alt_m_msl": null,
                "alt_m_agl": null
            },
            "device_time_ms": null,
            "timestamp": "",
            "unixtimestamp": 0,
            "schema": "odin-rf1/detection/v2",
            "classification": null,
            "raw": {
                "registration": null,
                "gps_time": "",
                "encrypted_id": null,
                "raw_hex": "0x58,0x10,0x2,0x83,0x2,0xc3,0x1f"
            },
            "sensor": {
                "name": "aeris1",
                "lat": start_lat,
                "lon": start_lon,
                "position_source": "fixed"
            }
        };

        track.push(payloadObject);
    }
    return track;
}

let state = context.get("state");

if (!state) {
    node.status({ fill: "blue", shape: "dot", text: "Generating schema records..." });
    let all = [];
    for (let i = 0; i < totalTracks; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * spreadMeters;
        const dx = Math.cos(angle) * radius;
        const dy = Math.sin(angle) * radius;
        const [droneStartLat, droneStartLon] = offsetCoord(start_lat, start_lon, dx, dy);
        const droneSerial = "163DF8" + generateRandomHexString(8);
        const track = generateBowTrack(droneStartLat, droneStartLon, 8.0, droneSerial);
        all.push(...track);
    }

    state = { index: 0, data: all, lastSerial: null };
    context.set("state", state);
    node.status({ fill: "green", shape: "dot", text: "Streaming to odin-rf1..." });
    sendNext();
    return;
}

function sendNext() {
    let state = context.get("state");
    if (!state || state.index >= state.data.length) {
        node.status({ fill: "grey", shape: "ring", text: "Finished." });
        context.set("state", null);
        return;
    }

    const msgOut = state.data[state.index];
    const now = new Date();

    msgOut.timestamp = now.toISOString();
    msgOut.unixtimestamp = now.getTime();
    msgOut.raw.gps_time = now.getTime().toString();

    const currentSerial = msgOut.serial;
    let delay = 1000;

    if (state.lastSerial && currentSerial !== state.lastSerial) {
        delay = pauseBetweenTracks;
    }

    state.lastSerial = currentSerial;
    state.index++;
    context.set("state", state);

    node.send({ payload: msgOut });
    setTimeout(sendNext, delay);
}

return;

