const now = Date.now();
const TIMEOUT_MS = 30000;

let trackInfo = activeTracks[droneId];
let isExpired = !trackInfo || (trackInfo.status !== 'pending' && (now - trackInfo.lastSeen >= TIMEOUT_MS));

msg.originalPayload = data;

// DROP intermediate frames while waiting for DB to prevent "shotgunning" the geofence
if (trackInfo && trackInfo.status === 'pending') {
    return [null, null];
}

if (trackInfo && !isExpired) {
    trackInfo.lastSeen = now;
    flow.set('activeTracks', activeTracks);
    msg.originalPayload.trackid = trackInfo.trackID;
    return [msg, null];
} else {
    // Lock the track state so we don't spam the DB with sequence requests
    activeTracks[droneId] = {
        status: 'pending'
    };
    flow.set('activeTracks', activeTracks);

    msg.query = `SELECT nextval('remoteid_trackid_seq') AS new_track_id;`;
    msg.droneId = droneId;
    return [null, msg];
}

const data = msg.originalPayload;
const newTrackId = msg.payload[0]?.new_track_id;
const droneId = msg.droneId;

if (!newTrackId) {
    node.error("Database did not return a new track_id.");
    return null;
}

data.trackid = newTrackId;

let activeTracks = flow.get('activeTracks') || {};
let pendingInfo = activeTracks[droneId];

activeTracks[droneId] = {
    trackID: newTrackId,
    lastSeen: Date.now(),
    status: 'active'
};
flow.set('activeTracks', activeTracks);

msg.originalPayload = data;

if (pendingInfo && pendingInfo.queue && pendingInfo.queue.length > 0) {
    pendingInfo.queue.forEach(queuedMsg => {
        queuedMsg.originalPayload.trackid = newTrackId;
        node.send([queuedMsg, null, null]);
    });
}

return msg;

